'use client';

import React, { useEffect, useState } from 'react';
import Link from 'next/link';
import { useAuth } from '@/context/AuthContext';
import {
    Search,
    Filter,
    Download,
    Plus,
    Activity,
    MoreHorizontal,
    ChevronRight
} from 'lucide-react';

const getStatusStyle = (status: string) => {
    switch (status) {
        case 'In Progress':
            return 'bg-teal-500 text-white';
        case 'Assigned':
            return 'bg-primary text-white';
        case 'Pending':
            return 'bg-warning text-dark';
        case 'New':
            return 'bg-secondary text-white';
        case 'Completed':
            return 'bg-success text-white';
        case 'Cancelled':
            return 'bg-danger text-white';
        default:
            return 'bg-light text-dark';
    }
};

const BookingsTable = ({ isFullMode = false }: { isFullMode?: boolean }) => {
    const { user } = useAuth();
    const [bookings, setBookings] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('All');

    useEffect(() => {
        const fetchBookings = async () => {
            try {
                setLoading(true);
                // Mocking data for visual consistency with design
                setBookings([
                    { id: 'BK-1047', patientName: 'Rajesh Kumar', serviceType: 'Post-Surgery Care', date: 'Today, 10:00 AM', status: 'In Progress', nurseName: 'Priya S.' },
                    { id: 'BK-1048', patientName: 'Lakshmi Devi', serviceType: 'Elderly Care', date: 'Today, 11:30 AM', status: 'Assigned', nurseName: 'Meena R.' },
                    { id: 'BK-1049', patientName: 'Venkat Reddy', serviceType: 'Wound Dressing', date: 'Today, 2:00 PM', status: 'Pending', nurseName: 'Not Assigned' },
                    { id: 'BK-1050', patientName: 'Anitha Menon', serviceType: 'Physiotherapy', date: 'Today, 3:30 PM', status: 'Assigned', nurseName: 'Kavitha M.' },
                    { id: 'BK-1051', patientName: 'Suresh Babu', serviceType: 'Dialysis Support', date: 'Today, 4:00 PM', status: 'Assigned', nurseName: 'Deepa K.' },
                    { id: 'BK-1052', patientName: 'Malathi S.', serviceType: 'Elderly Care', date: 'Tomorrow, 9:00 AM', status: 'New', nurseName: 'Not Assigned' },
                    { id: 'BK-1053', patientName: 'Karthik Iyer', serviceType: 'Injection Support', date: 'Today, 5:00 PM', status: 'Completed', nurseName: 'Priya S.' },
                    { id: 'BK-1054', patientName: 'Meera Krishnan', serviceType: 'Pediatric Care', date: 'Yesterday, 3:00 PM', status: 'Cancelled', nurseName: 'Divya L.' },
                ]);
            } catch (err) {
                console.error(err);
            } finally {
                setLoading(false);
            }
        };

        if (user) fetchBookings();
    }, [user]);

    const tabs = ['All', 'New Requests', 'Assigned', 'In Progress', 'Completed', 'Cancelled'];

    return (
        <div className="card border-0 shadow-sm rounded-2xl bg-white overflow-hidden animate-fade-in">
            {/* Header Content for Dashboard Overview */}
            {!isFullMode && (
                <div className="card-header bg-white border-bottom border-light p-4 d-flex align-items-center justify-content-between">
                    <div>
                        <h2 className="h5 fw-bold text-dark mb-0">Recent Bookings</h2>
                        <p className="text-muted small mb-0">Overview of latest service requests</p>
                    </div>
                    <Link href="/admin/bookings" className="btn btn-link link-teal-600 fw-bold text-decoration-none small">
                        View All <ChevronRight size={14} />
                    </Link>
                </div>
            )}

            {/* Tabs Section (Only in Full Mode) */}
            {isFullMode && (
                <div className="card-header bg-white border-bottom border-light p-0">
                    <ul className="nav nav-tabs border-0 px-4">
                        {tabs.map((tab) => (
                            <li key={tab} className="nav-item">
                                <button
                                    onClick={() => setActiveTab(tab)}
                                    className={`nav-link border-0 py-4 px-3 position-relative transition-300 ${activeTab === tab ? 'active text-teal-600 fw-bold' : 'text-secondary'}`}
                                    style={{ fontSize: '13px', letterSpacing: '0.5px' }}
                                >
                                    {tab.toUpperCase()}
                                    {activeTab === tab && (
                                        <span className="position-absolute bottom-0 start-0 w-100 bg-teal-600" style={{ height: '2px' }}></span>
                                    )}
                                </button>
                            </li>
                        ))}
                    </ul>
                </div>
            )}

            {/* Toolbar (Only in Full Mode) */}
            {isFullMode && (
                <div className="p-4 bg-light bg-opacity-10 d-flex align-items-center justify-content-between border-bottom border-light">
                    <div className="d-flex align-items-center gap-3">
                        <div className="position-relative" style={{ width: '300px' }}>
                            <Search className="position-absolute start-0 top-50 translate-middle-y ms-3 text-muted" size={16} />
                            <input
                                type="text"
                                placeholder="Filter bookings..."
                                className="form-control form-control-sm border-light bg-white ps-5 py-2 rounded-xl"
                            />
                        </div>
                        <button className="btn btn-outline-light border-light text-secondary d-flex align-items-center gap-2 px-3 py-2 rounded-xl hover-bg-light transition-300">
                            <Filter size={16} />
                            <span className="small fw-bold">Filter</span>
                        </button>
                    </div>
                    <div className="d-flex align-items-center gap-2">
                        <button className="btn btn-outline-light border-light text-secondary p-2 rounded-xl hover-bg-light transition-300">
                            <Download size={16} />
                        </button>
                        <button className="btn btn-teal-600 d-flex align-items-center gap-2 px-4 py-2 rounded-xl fw-bold shadow-sm transition-300">
                            <Plus size={18} strokeWidth={3} />
                            <span className="small">NEW BOOKING</span>
                        </button>
                    </div>
                </div>
            )}

            {/* Table Section */}
            <div className="table-responsive">
                <table className="table table-hover align-middle mb-0">
                    <thead className="bg-light bg-opacity-25 border-bottom border-light">
                        <tr>
                            <th className="px-4 py-3 text-secondary text-uppercase tracking-wider fw-bold" style={{ fontSize: '11px' }}>ID</th>
                            <th className="px-4 py-3 text-secondary text-uppercase tracking-wider fw-bold" style={{ fontSize: '11px' }}>Patient</th>
                            <th className="px-4 py-3 text-secondary text-uppercase tracking-wider fw-bold" style={{ fontSize: '11px' }}>Service</th>
                            <th className="px-4 py-3 text-secondary text-uppercase tracking-wider fw-bold" style={{ fontSize: '11px' }}>Nurse</th>
                            <th className="px-4 py-3 text-secondary text-uppercase tracking-wider fw-bold" style={{ fontSize: '11px' }}>Schedule</th>
                            <th className="px-4 py-3 text-secondary text-uppercase tracking-wider fw-bold text-center" style={{ fontSize: '11px' }}>Status</th>
                            <th className="px-4 py-3 text-secondary text-uppercase tracking-wider fw-bold text-center" style={{ fontSize: '11px' }}>Actions</th>
                        </tr>
                    </thead>
                    <tbody className="border-0">
                        {bookings
                            .filter(b => activeTab === 'All' || (activeTab === 'New Requests' && b.status === 'New') || b.status === activeTab)
                            .map((b: any, index) => (
                                <tr key={b.id} className="border-bottom border-light transition-300 animate-fade-in" style={{ animationDelay: `${index * 50}ms` }}>
                                    <td className="px-4 py-3">
                                        <span className="text-teal-600 fw-bold cursor-pointer hover-underline text-uppercase" style={{ fontSize: '13px' }}>{b.id}</span>
                                    </td>
                                    <td className="px-4 py-3 fw-extrabold text-dark" style={{ fontSize: '14px' }}>
                                        {b.patientName}
                                    </td>
                                    <td className="px-4 py-3">
                                        <div className="d-flex align-items-center gap-2 text-secondary" style={{ fontSize: '13px' }}>
                                            <div className="bg-light p-1 rounded-circle d-flex align-items-center justify-content-center" style={{ width: '24px', height: '24px' }}>
                                                <Activity size={12} className="text-teal-600" />
                                            </div>
                                            {b.serviceType}
                                        </div>
                                    </td>
                                    <td className="px-4 py-3">
                                        {b.nurseName !== 'Not Assigned' ? (
                                            <div className="d-flex align-items-center gap-2">
                                                <div className="bg-teal-50 text-teal-100 rounded-circle d-flex align-items-center justify-content-center fw-bold border border-teal-100 shadow-xs" style={{ width: '28px', height: '28px', fontSize: '10px', color: '#0D9488' }}>
                                                    {b.nurseName.split(' ').map((n: any) => n[0]).join('')}
                                                </div>
                                                <span className="text-dark fw-semibold" style={{ fontSize: '13px' }}>{b.nurseName}</span>
                                            </div>
                                        ) : (
                                            <span className="badge bg-danger bg-opacity-10 text-danger rounded-pill px-3 py-1 fw-bold" style={{ fontSize: '10px' }}>UNASSIGNED</span>
                                        )}
                                    </td>
                                    <td className="px-4 py-3 text-secondary" style={{ fontSize: '13px' }}>
                                        {b.date}
                                    </td>
                                    <td className="px-4 py-3 text-center">
                                        <span className={`badge rounded-pill px-3 py-2 fw-bold text-uppercase ${getStatusStyle(b.status)}`} style={{ fontSize: '10px' }}>
                                            {b.status}
                                        </span>
                                    </td>
                                    <td className="px-4 py-3 text-center">
                                        <button className="btn btn-link link-secondary p-2 hover-bg-light rounded-xl transition-300 border-0">
                                            <MoreHorizontal size={18} />
                                        </button>
                                    </td>
                                </tr>
                            ))}
                    </tbody>
                </table>
            </div>

            {/* Pagination (Only in Full Mode) */}
            {isFullMode && (
                <div className="p-4 bg-white d-flex align-items-center justify-content-between border-top border-light">
                    <p className="text-secondary mb-0" style={{ fontSize: '13px' }}>Showing <b>1</b> to <b>10</b> of <b>48</b> results</p>
                    <nav>
                        <ul className="pagination pagination-sm mb-0 gap-2">
                            <li className="page-item ripple"><button className="btn btn-outline-light border-light text-secondary px-3 py-2 rounded-xl hover-bg-light disabled">Previous</button></li>
                            <li className="page-item active"><button className="btn btn-teal-600 px-3 py-2 rounded-xl fw-bold text-white border-0">1</button></li>
                            <li className="page-item"><button className="btn btn-outline-light border-light text-secondary px-3 py-2 rounded-xl hover-bg-light">2</button></li>
                            <li className="page-item"><button className="btn btn-outline-light border-light text-secondary px-3 py-2 rounded-xl hover-bg-light">3</button></li>
                            <li className="page-item"><button className="btn btn-outline-light border-light text-secondary px-3 py-2 rounded-xl hover-bg-light">Next</button></li>
                        </ul>
                    </nav>
                </div>
            )}
        </div>
    );
};

export default BookingsTable;
